#include <iostream>
#include <list>

using namespace std;

int main()
{
    list<int> numbers;
    numbers.push_back(20);
    numbers.push_front(10);
    numbers.push_back(30);

    for (list<int>::iterator it = numbers.begin(); it != numbers.end(); it++)
    {
        cout << *it << " ";
    }

    return 0;
}

